/**
 * Provides the MagicBell context to all components in the SDK.
 *
 * Wrap your app in this component to enable access to the MagicBell API client,
 * local-first user/session state, and shared configuration. Required for components
 * like `Inbox`, `FloatingInbox`, and `SlackButton` to function.
 */
type Props = {
    /**
     * The MagicBell User JWT
     */
    token: string;
    /**
     * Override the base API URL (used for testing/staging).
     * @internal
     */
    baseUrl?: string;
    /**
     * Override the socket server URL (used for testing/staging).
     * @internal
     */
    socketUrl?: string;
    /**
     * Enable or disable toast notifications.
     * @default true
     */
    toasts?: boolean;
    /**
     * Elements to render inside the provider.
     * @type {Element}
     */
    children?: any;
};
declare function ContextProvider(props: Props): import("react/jsx-runtime").JSX.Element;
export default ContextProvider;

/**
 * A floating version of the notification inbox, toggled by a button.
 *
 * Renders the inbox inside a floating panel positioned relative to a trigger.
 * Ideal for embedding in navigation bars or headers. Supports full customization
 * of placement, dimensions, trigger, and inbox content.
 *
 * @event { notification: Notification } mb-notification-click - Emitted when a notification item is clicked. Call event.preventDefault() to stop default navigation.
 */
type FloatingInboxProps = {
    /**
     * The width of the floating inbox panel in pixels.
     * @default 400
     */
    width?: FloatingUIProps["width"];
    /**
     * The height of the floating inbox panel in pixels.
     * @default 400
     */
    height?: FloatingUIProps["height"];
    /**
     * Offset of the inbox from the trigger button, in pixels.
     * Can be a single number or an object with main/cross axis.
     * @type {OffsetOptions}
     * @default 8
     */
    offset?: FloatingUIProps["offset"];
    /**
     * Where to place the inbox relative to the trigger button.
     * E.g. 'bottom-end', 'top-start', etc.
     * @type {Placement}
     * @default bottom-start
     */
    placement?: FloatingUIProps["placement"];
    /**
     * Whether the inbox should be open by default.
     * @default false
     */
    defaultOpen?: FloatingUIProps["defaultOpen"];
    /**
     * Controlled open state. When provided, component becomes controlled
     * and will not close on outside click or Escape by itself.
     */
    open?: FloatingUIProps["open"];
    /**
     * Called whenever the user intends to change the open state.
     * Receives the next state and the reason: 'toggle' | 'outside' | 'escape'.
     */
    onOpenChange?: FloatingUIProps["onOpenChange"];
    /**
     * Called when a notification item is clicked.
     * Call `event.preventDefault()` to prevent the default behavior.
     */
    onNotificationClick?: (event: Event, detail: {
        notification: Notification;
    }) => void;
    /**
     * The component used to trigger the inbox, typically a bell icon.
     * It will receive `onClick` and `ref` props.
     * @type {Component}
     * @default InboxButton
     */
    ButtonComponent?: FloatingUIProps["TriggerComponent"];
    /**
     * The inbox component to render inside the floating panel.
     * Defaults to `<Inbox />` if not provided.
     * @type {Component}
     * @default Inbox
     */
    InboxComponent?: FloatingUIProps["FloatingComponent"];
};
import type { Notification } from "magicbell-js/user-client";
import type { FloatingUIProps } from "./internal/components/floating-ui.js";
declare function FloatingInbox(props: FloatingInboxProps): import("react/jsx-runtime").JSX.Element;
export default FloatingInbox;

/**
 * A notification inbox component that displays a list of notifications for the current user.
 *
 * Supports pagination, read/unread states, and customizable rendering of notification items.
 * Can be embedded directly in a page or used in combination with floating UIs using FloatingInbox.
 *
 * @event { notification: Notification } mb-notification-click - Emitted when a notification item is clicked. Call event.preventDefault() to stop default navigation.
 **/
type Props = {
    /**
     * Passed through by a parent component when rendering the FloatingInbox
     * @internal
     * @default false
     */
    floating?: boolean;
    /**
     * Set the height of the inbox.
     * @default 400
     */
    height?: number;
    /**
     * Estimated item height. It gets measured after mount, but it helps to estimate
     * this to limit layout shift.
     * @default 50
     */
    itemHeight?: number;
    /**
     * Component to use as Notification Item. The component receives two props;
     * `index: number` and `data: Notification`.
     * @type {Component}
     */
    ItemComponent?: any;
    /**
     * Called when a notification item is clicked.
     * Call `event.preventDefault()` to prevent the default behavior.
     */
    onNotificationClick?: (event: Event, detail: {
        notification: Notification;
    }) => void;
};
import type { Notification } from "magicbell-js/user-client";
declare function Inbox(props: Props): import("react/jsx-runtime").JSX.Element;
export default Inbox;

export type OpenChangeReason = "toggle" | "outside" | "escape";
export type OpenChangeMeta = {
    reason: OpenChangeReason;
    event?: Event;
};
export type FloatingUIProps = {
    placement?: Placement;
    width?: number;
    height?: number;
    offset?: OffsetOptions;
    defaultOpen?: boolean;
    open?: boolean;
    onOpenChange?: (open: boolean, meta: OpenChangeMeta) => void;
    TriggerComponent: any;
    FloatingComponent: any;
    floatingComponentProps?: any;
    data?: any;
};
import type { OffsetOptions, Placement } from "@floating-ui/dom";
declare function FloatingUI(props: FloatingUIProps): import("react/jsx-runtime").JSX.Element;
export default FloatingUI;

import { Client } from "magicbell-js/user-client";
import { NotificationStore } from "../stores/notification-store.js";
import { RealtimeStore } from "../stores/realtime-store.js";
export type MagicBellContext = {
    client: Client;
    socket: RealtimeStore;
    notifications: NotificationStore;
    sessionId: string;
};
export type MagicBellProviderProps = {
    token: string;
    baseUrl?: string;
    socketUrl?: string;
    children?: any;
};
export declare function getSessionId(): string;
export declare function createMagicBellContext(props: MagicBellProviderProps): MagicBellContext;

import type { Client, Notification } from "magicbell-js/user-client";
import { Collection } from "tinycoll";
import type { RealtimeStore } from "./realtime-store.js";
type Options = {
    client: Client;
    socket: RealtimeStore;
};
type Meta = {
    lastFetched: number;
    userId: string;
};
export declare class NotificationStore extends Collection<Notification, Meta> {
    #private;
    constructor(options: Options);
    stopPolling(): void;
    fetchMore(): Promise<void>;
    markAsRead(id: string): void;
    markAsUnread(id: string): void;
    markAllRead(): void;
    archive(id: string): void;
}
export {};

