:root {
  --magicbell-font-family: Verdana, Tahoma, sans-serif;

  --magicbell-text-dimm: #EDEDEF;
  --magicbell-text-muted: #A09FA6;
  --magicbell-text-default: #3b3b3b;
  --magicbell-text-contrast: #EDEDEF;
  --magicbell-text-highlight: #FFEF5C;
  --magicbell-text-link: #6E56CF;
  --magicbell-text-link-hover: #7C66DC;
  --magicbell-text-link-active: #9E8CFC;
  --magicbell-text-info: #849DFF;
  --magicbell-text-success: #63C174;
  --magicbell-text-warning: #F1A10D;
  --magicbell-text-error: #F16A50;

  --magicbell-bg-default: #fff;
  --magicbell-bg-active: #f8f5ff;
