  --magicbell-error-bg: #E54D2E;
  --magicbell-error-bg-hover: #EC5E41;
  --magicbell-error-bg-active: #F17B5A;

  --magicbell-success-bg: #46A758;
  --magicbell-success-bg-hover: #5DB46B;
  --magicbell-success-bg-active: #7AC58A;

  --magicbell-border-muted: #EDEDEF;
  --magicbell-border-default: #A09FA6;
  --magicbell-border-highlight: #4D5E94;

  --magicbell-spacing-xs: 0.25rem;
  --magicbell-spacing-sm: 0.5rem;
  --magicbell-spacing-md: 0.75rem;
  --magicbell-spacing-lg: 1rem;
  --magicbell-spacing-xl: 1.5rem;

  --magicbell-radius-xs: 0.125rem;
  --magicbell-radius-sm: 0.25rem;
  --magicbell-radius-md: 0.5rem;
  --magicbell-radius-lg: 0.75rem;
  --magicbell-radius-xl: 1rem;

  --magicbell-shadow-base: 0px -1px 1px 0px rgba(0, 0, 0, .05), 0px 1px 2px 0px rgba(0, 0, 0, .15);
  --magicbell-shadow-elevated: 0px -1px 1px 0px rgba(0, 0, 0, .05), 0px 8px 14px 3px rgba(31, 41, 51, .08), 0px 2px 2px 0px rgba(0, 0, 0, .07)
}

@keyframes magicbell-fade-in-up {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes magicbell-fade-out-down {
  from {
    opacity: 1;
    transform: translateY(0);
  }
  to {
    opacity: 0;
    transform: translateY(10px);
  }
}

@keyframes magicbell-pulse {
  0% {
    transform: scale(.33);
  }
  80%, 100% {
    opacity: 0;
  }
}

@keyframes magicbell-scale-in {
  from {
    opacity: 0;
    transform: scale(0);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes magicbell-scale-out {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0);
  }
}

.magicbell--floating-menu {
  display: block;
  box-shadow: var(--magicbell-shadow-base);
  margin: 0;
  padding: var(--magicbell-spacing-xs) 0;
  background: var(--magicbell-surface-bg);
  border-radius: var(--magicbell-radius-sm);
  list-style: none;
}

.magicbell--floating-menu--item {
  display: block;
  white-space: nowrap;
}

.magicbell--floating-menu--item > button {
  font-family: var(--magicbell-font-family);
  font-size: 0.875rem;
  color: var(--magicbell-surface-text);
  border: none;
  padding: var(--magicbell-spacing-sm) var(--magicbell-spacing-lg);
  margin: 0;
  background: none;
  width: 100%;
  text-align: left;
  cursor: pointer;
}

.magicbell--floating-menu--item > button:hover, .magicbell--floating-menu--item > button:focus {
  background-color: var(--magicbell-surface-bg-hover);
  color: var(--magicbell-surface-text-hover);
}

.magicbell--floating-menu--item > button:active {
  background-color: var(--magicbell-surface-bg-active);
  color: var(--magicbell-surface-text-active);
}

.magicbell--menu-button {
  color: var(--magicbell-text-default);
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  background: none;
  cursor: pointer;
}

.magicbell--inbox {
  font-family: var(--magicbell-font-family);
  background-color: var(--magicbell-bg-default);
  border: 1px solid var(--magicbell-border-muted);
  border-radius: var(--magicbell-radius-lg);
  overflow: hidden;
}

.magicbell--inbox[data-floating="true"] {
  box-shadow: var(--magicbell-shadow-elevated);
  overflow: hidden;
}

.magicbell--inbox-header {
  display: flex;
  padding: 0 1rem;
  gap: .75rem;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid var(--magicbell-border-muted);
}

.magicbell--inbox-header--title {
  font-size: 1rem;
  font-weight: 600;
  color: var(--magicbell-text-default);
  padding: 0.75rem 0;
}

.magicbell--inbox-header--actions {
  display: flex;
  gap: var(--magicbell-spacing-sm);
}

.magicbell--inbox-header--button {
  font-family: var(--magicbell-font-family);
  font-size: 0.875rem;
  padding: var(--magicbell-spacing-xs);
  border: none;
  color: var(--magicbell-text-default);
  background: none;
  cursor: pointer;
  border-radius: var(--magicbell-radius-sm);
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.magicbell--inbox-header--button svg {
  width: 1.25rem;
  height: 1.25rem;
}

.magicbell--inbox-header--button:hover, .magicbell--inbox-header--button:focus {
  background-color: var(--magicbell-bg-hover);
}

.magicbell--inbox-footer {
  padding: .5rem 1rem;
  border-top: 1px solid var(--magicbell-border-muted);
  line-height: 1rem;
  display: flex;
  align-items: center;
}

.magicbell--inbox-footer--logo, .magicbell--inbox-footer--logo a {
  display: inline-flex;
  align-items: center;
  color: #5225c1;
  line-height: 1rem;
}

.magicbell--inbox-item {
  width: 100%;
  height: 100%;
  padding: .5rem 1rem;
  display: grid;
  grid-template-areas:
    "title date"
    "content action";
  grid-template-columns: 1fr auto;
  grid-template-rows: auto auto;
  font-size: .875rem;
  line-height: 1.4;
  color: var(--magicbell-text-default);
  cursor: pointer;
}

.magicbell--inbox-item:not(:last-child) {
  border-bottom: 1px solid var(--magicbell-border-muted);
}

.magicbell--inbox-item[data-status="unread"] {
  background-color: var(--magicbell-bg-active);
}

.magicbell--inbox-item:not(:has(.magicbell--inbox-item--content)) {
  grid-template-areas:
    "title date"
    "title action";
  grid-template-columns: 1fr auto;
  grid-template-rows: auto auto;
}

.magicbell--inbox-item:hover, .magicbell--inbox-item:focus-within {
  background-color: var(--magicbell-bg-hover);
}

.magicbell--inbox-item .magicbell--menu-button {
  opacity: 0;
  transition: opacity 0.2s ease-in-out;
}

.magicbell--inbox-item .magicbell--menu-button svg {
  transform: rotate(90deg);
}

.magicbell--inbox-item:hover .magicbell--menu-button, .magicbell--inbox-item:focus-within .magicbell--menu-button {
  opacity: 1;
}

.magicbell--inbox-item--action {
  grid-area: action;
  margin: .5rem 0 0 .5rem;
  justify-self: end;
}

.magicbell--inbox-item--title {
  grid-area: title;
  margin: .5rem 0 0 0;
}

.magicbell--inbox-item--date {
  grid-area: date;
  font-size: .75rem;
  color: var(--magicbell-text-muted);
  margin: .5rem 0 0 0;
}

.magicbell--inbox-item--content {
  grid-area: content;
  margin: .5rem 0;
  line-clamp: 3;
  -webkit-line-clamp: 3;
  text-overflow: ellipsis;
  overflow: hidden;
  display: -webkit-box;
  -webkit-box-orient: vertical;
}

.magicbell--inbox--empty-state {
  font-family: var(--magicbell-font-family);
  color: var(--magicbell-text-default);
  font-size: 0.875rem;
  font-style: italic;
  text-align: center;
  padding: 2.5rem;
  overflow: hidden;
}

.magicbell--inbox--empty-state p {
  margin: 0;
}

.magicbell--inbox--empty-state img {
  display: block;
  margin: 2rem auto;
}

.magicbell--inbox .magicbell--user-preferences {
  padding: 1rem;
  overflow-y: auto;
  scrollbar-gutter: stable;
  height: 100%;
}

.magicbell--notification-bar {
  font-family: var(--magicbell-font-family);
  background: var(--magicbell-primary-bg);
  color: var(--magicbell-text-default);
  width: 100%;
  padding: .5rem 1rem;

  display: grid;
  grid-template-areas:
    "title content action";
  grid-template-columns: auto 1fr auto;
  font-size: .875rem;
}

.magicbell--notification-bar--title {
  grid-area: title;
  align-self: center;
}

.magicbell--notification-bar--date {
  display: none;
  font-size: .75rem;
  color: var(--magicbell-text-muted);
}

.magicbell--notification-bar--action {
  grid-area: action;
  display: flex;
  align-items: center;
}

.magicbell--notification-bar--content {
  grid-area: content;
}

.magicbell--inline-notification[data-variant="bar"][data-status="active"] {
  animation-name: magicbell-fade-in-up;
}

.magicbell--inline-notification[data-variant="bar"][data-status="inactive"] {
  animation-name: magicbell-fade-out-down;
}

.magicbell--notification-dot {
  background: rgb(229, 77, 46);
  width: 8px;
  height: 8px;
  border-radius: 50%;
  position: relative;
  animation: pulse 2s infinite;
}

.magicbell--notification-dot:before {
  content: '';
  display: block;
  width: 300%;
  height: 300%;
  box-sizing: border-box;
  position: absolute;
  left: 0;
  top: 0;
  margin-top: -100%;
  margin-left: -100%;
  border-radius: 50%;
  background: rgb(229, 77, 46);
  animation: magicbell-pulse 1.5s cubic-bezier(0.215, 0.61, 0.355, 1) infinite;
}

.magicbell--inline-notification {
  width: 100%;
  height: 100%;
  animation-duration: 0.3s;
  animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);
  animation-fill-mode: both;
}

.magicbell--inline-notification[data-variant="dot"][data-status="active"] {
  animation-name: magicbell-scale-in;
}

.magicbell--inline-notification[data-variant="dot"][data-status="inactive"] {
  animation-name: magicbell-scale-out;
}

/** further animations are applied via the children **/

.magicbell--inbox-button {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.magicbell--inbox-button-badge {
  position: absolute;
  top: 0;
  right: 0;
  transform: translate(35%, -35%);
}

.magicbell--inbox[data-floating="true"] {
  box-shadow: var(--magicbell-shadow-elevated);
  overflow: hidden;
}

