    if (!ctx || !ctx.notifications) return;

    const observer = ctx.notifications
      .find({
        discardedAt: null,
        archivedAt: null,
      }, {
        sort: { sentAt: -1 },
      })
      .watch((docs) => {
        setReady(true);
        setAllNotifications(docs);
      });

