      {view === 'inbox' && ready && filteredNotifications.length > 0 && (
        <div style={{ height: `${inboxHeight}px`, overflowY: 'auto' }}>
          {filteredNotifications.map((notification, index) => (
            <NotificationItem
              key={notification.id || index}
              notification={notification}
              onMarkRead={() => ctx.notifications.markAsRead(notification.id)}
            />
          ))}
        </div>
      )}

      {view === 'inbox' && ready && filteredNotifications.length === 0 && (
        <div className="magicbell--inbox--empty-state" style={{ height: `${inboxHeight}px` }}>
          <p>{activeTab === 'unread' ? 'No unread notifications' : 'No notifications yet'}</p>
        </div>
      )}

